1	const BASE_PRICE_BY_TYPE: Record<string, number> = {
2	  potion: 40,
3	  amulet: 60,
4	  staff: 80,
5	  sword: 100,
6	  rune: 25,
7	  moonstone: 25,
8	};
9	const RUNE_COMPONENT_TYPES = new Set(["rune", "moonstone"]);
10	const RUNE_COMPONENT_BLOCK_SIZE = 3;
11	const RUNE_COMPONENT_BLOCK_PRICE = 60;
12	
13	const HIGH_ENCHANTMENT_THRESHOLD = 5;
14	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
15	
16	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
17	const PROCESSING_FEE = 5;
18	
19	export function quote(input: { customer: { yearsWithMHPCO: number }; items: { type: string; enchantment?: number; cursed?: boolean }[] }): number {
20	  const items = input.items;
21	  const countByType: Record<string, number> = {};
22	  for (const item of items) {
23	    countByType[item.type] = (countByType[item.type] ?? 0) + 1;
24	  }
25	  let basePrice = 0;
26	  for (const type of Object.keys(countByType)) {
27	    const count = countByType[type];
28	    const formsRuneBlock = RUNE_COMPONENT_TYPES.has(type) && count === RUNE_COMPONENT_BLOCK_SIZE;
29	    if (formsRuneBlock) {
30	      basePrice += RUNE_COMPONENT_BLOCK_PRICE;
31	    } else {
32	      basePrice += count * BASE_PRICE_BY_TYPE[type];
33	    }
34	  }
35	  let highEnchantmentSurcharges = 0;
36	  for (const item of items) {
37	    if ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD) {
38	      highEnchantmentSurcharges += BASE_PRICE_BY_TYPE[item.type] * HIGH_ENCHANTMENT_SURCHARGE_RATE;
39	    }
40	  }
41	  const firstInsuranceSurcharge = basePrice * FIRST_INSURANCE_SURCHARGE_RATE;
42	  const premium = basePrice + highEnchantmentSurcharges + firstInsuranceSurcharge + PROCESSING_FEE;
43	  return Math.ceil(premium);
44	}
